  // ── Canada ──
  edmonton: { slug: "edmonton", name: "Edmonton", state: "Alberta", country: "Canada", region: "Edmonton, St. Albert, Sherwood Park, and the greater Edmonton metropolitan area", description: "Alberta's capital city and a major hub for oil, tech, and innovation", landmarks: ["Downtown Edmonton", "Whyte Avenue", "West Edmonton Mall", "Ice District", "104 Street NW"], industries: ["oil & gas", "tech startups", "government", "construction", "agriculture", "healthcare", "education", "logistics"], uniqueContent: ["Edmonton is home to TML Agency's Canadian office at 11930 104 St NW. We serve businesses across Alberta including Calgary, Red Deer, and Fort McMurray with local expertise and competitive pricing.", "As Alberta's capital, Edmonton's economy is diversifying rapidly from oil & gas into tech, clean energy, and innovation. Businesses here need digital marketing partners who understand both the traditional industries and the emerging startup ecosystem.", "Our Edmonton team provides bilingual support (English/Punjabi) and understands the unique cultural landscape of Alberta's business community. From Ice District developments to Whyte Avenue retail, we help Edmonton businesses compete digitally."] },
  calgary: { slug: "calgary", name: "Calgary", state: "Alberta", country: "Canada", region: "Calgary, Airdrie, Cochrane, and southern Alberta", description: "Canada's energy capital and a growing tech hub", landmarks: ["Downtown Calgary", "Stephen Avenue", "Kensington", "Beltline", "University District"], industries: ["oil & gas", "finance", "tech", "agriculture", "tourism", "construction", "film"], uniqueContent: ["Calgary's energy sector is the backbone of Alberta's economy, but the city's tech corridor along Stephen Avenue and the Beltline is growing fast. TML helps Calgary businesses bridge the gap between traditional oil & gas marketing and modern digital-first strategies that attract talent and clients.", "The Calgary market is fiercely competitive, with businesses on Stephen Avenue, in Kensington, and across the Beltline all vying for the same digitally engaged consumer. Our geo-targeted campaigns and local SEO strategies ensure your Calgary business appears exactly where your customers are searching.", "From our Edmonton office, TML serves Calgary clients with the advantage of Alberta-based understanding and face-to-face collaboration. We know Calgary's boom-and-bust cycles, the Stampede marketing window, and how to position brands for both the energy executive in the Bow Tower and the creative entrepreneur in the East Village."] },
  airdrie: { slug: "airdrie", name: "Airdrie", state: "Alberta", country: "Canada", region: "Airdrie, Balzac, and the Calgary-Edmonton corridor", description: "One of Canada's fastest-growing cities just north of Calgary", landmarks: ["Main Street Airdrie", "Sierra Springs", "Genesis Place", "Balzac CrossIron Mills", "Yankee Valley Crossing"], industries: ["construction", "retail", "healthcare", "professional services", "real estate", "logistics", "food & beverage"], uniqueContent: ["Airdrie has exploded from a small bedroom community into one of Canada's fastest-growing cities, with new residential developments like Sierra Springs and Ravenswood drawing thousands of young families every year. Main Street Airdrie is experiencing a revival with independent shops, restaurants, and service businesses competing for local attention. The proximity to CrossIron Mills in Balzac adds a major retail corridor that Airdrie businesses must contend with digitally.", "The city's economy runs on construction, real estate, healthcare, and the professional services that support a rapidly expanding population. Neighbourhoods like Coopers Crossing, Reunion, and Bayview are full of homeowners searching for local contractors, dental clinics, and family services. Airdrie's location on the QE2 corridor also makes it a logistics and warehousing hub between Calgary and Red Deer.", "Town Media Labs helps Airdrie businesses stand out in a market where new competitors arrive monthly. Our hyperlocal SEO ensures your business ranks for Airdrie-specific searches rather than being buried under Calgary results. From Google Ads targeting the QE2 corridor commuter to social media campaigns that build community loyalty, TML gives Airdrie businesses a digital edge that matches their city's growth."] },
