export const allLocationSlugs = Object.keys(locations);

export interface LocationServiceDef {
  serviceSlug: string;
  serviceName: string;
  locationSlug: string;
  urlSlug: string;
}

const serviceList = [
  { slug: "branding", name: "Branding" },
  { slug: "google-ads", name: "Google Ads" },
  { slug: "seo", name: "SEO" },
  { slug: "website-development", name: "Website Development" },
  { slug: "social-media", name: "Social Media Marketing" },
  { slug: "ai-influencer-management", name: "AI Influencer Management" },
  { slug: "lead-generation", name: "Lead Generation" },
  { slug: "music-release", name: "Music Release" },
  { slug: "video-editing", name: "Video Editing" },
  { slug: "branding-packaging", name: "Packaging Design" },
  { slug: "graphic-design", name: "Graphic Design" },
];

export function getLocationServiceSlug(serviceSlug: string, locationSlug: string): string {
  const loc = locationSlug.replace(/_/g, "-");
  if (serviceSlug === "social-media") return `social-media-marketing-in-${loc}`;
  return `${serviceSlug}-in-${loc}`;
}

export function getAllLocationServiceDefs(): LocationServiceDef[] {
  const defs: LocationServiceDef[] = [];
  for (const loc of Object.values(locations)) {
    for (const svc of serviceList) {
      defs.push({
        serviceSlug: svc.slug,
        serviceName: svc.name,
        locationSlug: loc.slug,
        urlSlug: getLocationServiceSlug(svc.slug, loc.slug),
      });
    }
  }
  return defs;
}

export const allLocationServiceSlugs = getAllLocationServiceDefs().map((d) => d.urlSlug);

export { serviceList };
